import React, { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Points, PointMaterial, Environment } from '@react-three/drei';
import * as random from 'maath/random/dist/maath-random.esm';

function StarField(props) {
    const ref = useRef();

    // Create a sphere of random points
    const sphere = random.inSphere(new Float32Array(5000 * 3), { radius: 1.5 });

    useFrame((state, delta) => {
        // Rotate the stars slowly
        if (ref.current) {
            ref.current.rotation.x -= delta / 10;
            ref.current.rotation.y -= delta / 15;
        }
    });

    return (
        <group rotation={[0, 0, Math.PI / 4]}>
            <Points ref={ref} positions={sphere} stride={3} frustumCulled={false} {...props}>
                <PointMaterial
                    transparent
                    color="#8b5cf6"
                    size={0.005}
                    sizeAttenuation={true}
                    depthWrite={false}
                    blending={2} // Additive blending for glow effect
                />
            </Points>
        </group>
    );
}

export default function Background3D() {
    return (
        <div className="canvas-container">
            <Canvas camera={{ position: [0, 0, 1] }}>
                <Environment preset="night" />
                <StarField />
            </Canvas>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useRealTimeRates } from '../hooks/useRealTimeRates';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, Area, AreaChart, CartesianGrid } from 'recharts';
import { ArrowUpDown, Activity, TrendingUp, TrendingDown, AlertCircle } from 'lucide-react';
import clsx from 'clsx'; // utility added via npm

export default function CurrencyArbitrator() {
    const [base, setBase] = useState('INR');
    const [target, setTarget] = useState('USD');
    const [amount, setAmount] = useState(50000);
    const [isSwapping, setIsSwapping] = useState(false);

    const { currentRate, historicalData, loading, currencies } = useRealTimeRates(base, target);

    const convertedAmount = currentRate ? (amount * currentRate).toFixed(2) : 0;
    const currentPrediction = historicalData[historicalData.length - 1]?.predictive;

    // Calculate potential difference over 1hr
    const deltaValue = currentPrediction ? (convertedAmount - (amount * currentPrediction)).toFixed(2) : 0;
    const trend = deltaValue > 0 ? 'up' : 'down';
    const colorClass = trend === 'up' ? 'text-[#10b981]' : 'text-[#ef4444]';
    const bgWarningClass = trend === 'up' ? 'bg-[#10b981]/10 border-[#10b981]/30' : 'bg-[#ef4444]/10 border-[#ef4444]/30';

    const handleSwap = () => {
        setIsSwapping(true);
        setTimeout(() => {
            setBase(target);
            setTarget(base);
            setIsSwapping(false);
        }, 300);
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            {/* Exchange Card */}
            <motion.div
                className="premium-glass p-8 lg:col-span-5 relative overflow-hidden flex flex-col justify-between min-h-[500px]"
                initial={{ opacity: 0, x: -50 }}
                whileInView={{ opacity: 1, x: 0 }}
                viewport={{ once: true }}
            >
                <div className="absolute top-0 right-0 w-64 h-64 bg-[#8b5cf6]/20 rounded-full blur-[100px] -z-10 pointer-events-none"></div>

                <div>
                    <div className="flex items-center gap-3 mb-10">
                        <div className="p-3 bg-[#8b5cf6]/20 rounded-xl border border-[#8b5cf6]/30 shadow-[0_0_20px_rgba(139,92,246,0.3)]">
                            <Activity className="text-[#8b5cf6]" size={24} />
                        </div>
                        <div>
                            <h3 className="text-xl font-bold tracking-tight">Active Conversion</h3>
                            <div className="flex items-center gap-2">
                                <span className="w-2 h-2 rounded-full bg-[#10b981] animate-pulse"></span>
                                <span className="text-xs text-[#10b981] font-mono tracking-widest uppercase">Live Link Active</span>
                            </div>
                        </div>
                    </div>

                    {/* From Input */}
                    <div className="group relative z-10 p-1 rounded-2xl bg-gradient-to-b from-white/5 to-white/0 mb-4 transition-all hover:bg-white/5">
                        <div className="flex justify-between items-center mb-2 px-2">
                            <label className="text-sm font-bold text-muted uppercase tracking-widest">You Request</label>
                            <select
                                className="bg-transparent text-white font-bold outline-none border-b border-white/20 pb-1 premium-select"
                                value={base}
                                onChange={e => setBase(e.target.value)}
                            >
                                {currencies.map(c => <option key={c} value={c} className="bg-black">{c}</option>)}
                            </select>
                        </div>
                        <input
                            type="number"
                            className="premium-input text-4xl font-black bg-black/40 border-none px-6 py-6"
                            value={amount}
                            onChange={e => setAmount(Number(e.target.value))}
                        />
                    </div>

                    <div className="flex justify-center -my-3 relative z-20">
                        <button
                            onClick={handleSwap}
                            className={clsx(
                                "w-12 h-12 rounded-xl bg-black border border-white/10 flex items-center justify-center text-white transition-all shadow-[0_0_20px_rgba(0,0,0,0.8)]",
                                "hover:border-[#0ea5e9] hover:text-[#0ea5e9] hover:shadow-[0_0_20px_rgba(14,165,233,0.4)]",
                                isSwapping && "animate-spin"
                            )}
                        >
                            <ArrowUpDown size={20} />
                        </button>
                    </div>

                    {/* To Input */}
                    <div className="group relative z-10 p-1 rounded-2xl bg-gradient-to-t from-[#0ea5e9]/5 to-transparent mt-4 transition-all border border-transparent hover:border-[#0ea5e9]/20">
                        <div className="flex justify-between items-center mb-2 px-2">
                            <label className="text-sm font-bold text-[#0ea5e9] uppercase tracking-widest">Client Pays</label>
                            <select
                                className="bg-transparent text-white font-bold outline-none border-b border-white/20 pb-1 premium-select"
                                value={target}
                                onChange={e => setTarget(e.target.value)}
                            >
                                {currencies.map(c => <option key={c} value={c} className="bg-black">{c}</option>)}
                            </select>
                        </div>
                        <div className="px-6 py-6 bg-black/40 rounded-xl border border-white/5 shadow-inner">
                            <p className="font-mono text-5xl font-black text-white truncate text-glow-primary">
                                {loading ? '...' : convertedAmount}
                            </p>
                        </div>
                    </div>
                </div>

                <div className="mt-8 pt-6 border-t border-white/10 flex justify-between items-center text-sm">
                    <span className="text-muted font-mono bg-black/50 px-3 py-1 rounded-md">
                        1 {base} = {currentRate?.toFixed(4)} {target}
                    </span>
                    <span className="text-[#8b5cf6] font-bold flex items-center gap-1">
                        <Activity size={14} /> 0% Dynamic Fee
                    </span>
                </div>
            </motion.div>

            {/* Analytics Chart */}
            <motion.div
                className="premium-glass p-8 lg:col-span-7 flex flex-col relative"
                initial={{ opacity: 0, x: 50 }}
                whileInView={{ opacity: 1, x: 0 }}
                viewport={{ once: true }}
            >
                <div className="absolute bottom-0 right-0 w-80 h-80 bg-[#0ea5e9]/10 rounded-full blur-[100px] -z-10 pointer-events-none"></div>

                <div className="flex justify-between items-start mb-8">
                    <div>
                        <h3 className="text-2xl font-black mb-1 flex items-center gap-2">
                            Volatility Predictor <span className="bg-[#8b5cf6] text-white text-xs px-2 py-1 rounded-md ml-2 tracking-widest uppercase">AI Engine</span>
                        </h3>
                        <p className="text-muted">Proprietary forecasting for perfect invoice timing.</p>
                    </div>
                    <div className={clsx("px-4 py-2 rounded-xl border flex items-center gap-2", bgWarningClass)}>
                        {trend === 'up' ? <TrendingUp className={colorClass} /> : <TrendingDown className={colorClass} />}
                        <div>
                            <p className="text-xs uppercase font-bold text-white/50 tracking-widest">1Hr Forecast</p>
                            <p className={clsx("font-black text-lg leading-none", colorClass)}>
                                {trend === 'up' ? '+' : ''}{deltaValue} {target}
                            </p>
                        </div>
                    </div>
                </div>

                <div className="flex-1 w-full min-h-[300px] max-h-[400px]">
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={historicalData} margin={{ top: 20, right: 30, left: 0, bottom: 0 }}>
                            <defs>
                                <linearGradient id="colorRate" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.4} />
                                    <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0} />
                                </linearGradient>
                                <linearGradient id="colorPred" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#0ea5e9" stopOpacity={0.4} />
                                    <stop offset="95%" stopColor="#0ea5e9" stopOpacity={0} />
                                </linearGradient>
                            </defs>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.05)" />
                            <XAxis dataKey="time" stroke="#475569" fontSize={11} tickMargin={10} axisLine={false} tickLine={false} />
                            <YAxis stroke="#475569" fontSize={11} domain={['auto', 'auto']} axisLine={false} tickLine={false} />
                            <Tooltip
                                contentStyle={{
                                    borderRadius: '12px',
                                    backgroundColor: 'rgba(5, 5, 10, 0.9)',
                                    border: '1px solid rgba(139,92,246,0.3)',
                                    boxShadow: '0 10px 30px rgba(0,0,0,0.5)',
                                    backdropFilter: 'blur(10px)'
                                }}
                                itemStyle={{ color: '#fff', fontWeight: 'bold' }}
                            />
                            <Area type="monotone" dataKey="rate" stroke="#8b5cf6" strokeWidth={3} fillOpacity={1} fill="url(#colorRate)" />
                            <Area type="monotone" dataKey="predictive" stroke="#0ea5e9" strokeWidth={3} strokeDasharray="5 5" fillOpacity={1} fill="url(#colorPred)" />
                        </AreaChart>
                    </ResponsiveContainer>
                </div>

                <div className="mt-6 flex items-center justify-between text-sm pt-4 border-t border-white/5">
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-2">
                            <span className="w-3 h-3 rounded-full bg-[#8b5cf6]"></span>
                            <span className="text-muted">Historical</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <span className="w-3 h-3 rounded-full bg-[#0ea5e9]"></span>
                            <span className="text-white font-bold">AI Prediction Algorithm</span>
                        </div>
                    </div>
                    <button className="text-[#0ea5e9] hover:text-white font-bold flex items-center gap-1 transition-colors">
                        Generate Report <ArrowUpDown size={14} className="rotate-90" />
                    </button>
                </div>
            </motion.div>
        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import { Keyboard, Crosshair, Cpu, Zap, RotateCcw } from 'lucide-react';
import clsx from 'clsx'; // utility added via npm

const TEXT = "In a global economy, arbitration mitigates exchange volatility. A true professional freelancer adapts to shifts using predictive models and flawless execution. Precision is mandatory. Speed is your asset. The algorithm demands perfection and rewards accuracy.";

export default function TypingTest() {
    const [input, setInput] = useState('');
    const [started, setStarted] = useState(false);
    const [timeLeft, setTimeLeft] = useState(30);
    const [wpm, setWpm] = useState(0);
    const [correct, setCorrect] = useState(0);
    const [accuracy, setAccuracy] = useState(0);
    const [completed, setCompleted] = useState(false);
    const inputRef = useRef(null);

    useEffect(() => {
        let timer;
        if (started && timeLeft > 0) {
            timer = setInterval(() => {
                setTimeLeft(prev => prev - 1);
            }, 1000);
        } else if (timeLeft === 0 && started) {
            finishTest();
        }
        return () => clearInterval(timer);
    }, [started, timeLeft]);

    const handleChange = (e) => {
        if (completed) return;
        const val = e.target.value;

        if (!started && val.length > 0) setStarted(true);
        setInput(val);

        let correctChars = 0;
        for (let i = 0; i < val.length; i++) {
            if (val[i] === TEXT[i]) correctChars++;
        }
        setCorrect(correctChars);
        setAccuracy(val.length > 0 ? (correctChars / val.length) * 100 : 0);

        if (val.length === TEXT.length) finishTest(correctChars);
    };

    const finishTest = (finalCorrect = correct) => {
        setStarted(false);
        setCompleted(true);
        const timeSpent = 30 - timeLeft;
        const finalWpm = timeSpent > 0 ? Math.round((finalCorrect / 5) / (timeSpent / 60)) : 0;
        setWpm(finalWpm);
    };

    const reset = () => {
        setInput('');
        setStarted(false);
        setCompleted(false);
        setTimeLeft(30);
        setWpm(0);
        setAccuracy(0);
        setCorrect(0);
        setTimeout(() => inputRef.current?.focus(), 100);
    };

    return (
        <motion.div
            className="premium-glass p-1 relative overflow-hidden group/container"
            initial={{ opacity: 0, scale: 0.95 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
        >
            <div className="absolute inset-x-0 bottom-0 h-1 bg-gradient-to-r from-[#10b981] via-[#0ea5e9] to-[#8b5cf6] opacity-30 shadow-[0_-5px_20px_rgba(14,165,233,0.5)] z-20"></div>

            <div className="bg-[#050508] p-8 lg:p-12 rounded-[22px] relative z-10">
                <div className="flex justify-between items-center mb-10">
                    <div>
                        <h3 className="text-3xl font-black mb-2 flex items-center gap-3">
                            <span className="text-white">Cognitive Check</span>
                            <Keyboard className="text-[#0ea5e9] animate-pulse" size={28} />
                        </h3>
                        <p className="text-[#8b96a5] font-mono text-sm tracking-widest uppercase">
                            Authenticate via keystroke dynamics
                        </p>
                    </div>

                    <div className="flex gap-4">
                        <div className="bg-[#10b981]/10 border border-[#10b981]/20 px-5 py-3 rounded-xl flex flex-col items-center min-w-[100px] shadow-[inset_0_0_20px_rgba(16,185,129,0.1)]">
                            <span className="text-[#10b981] font-bold text-xs uppercase tracking-widest mb-1">Time</span>
                            <span className="text-3xl font-black font-mono text-white text-glow-primary">{timeLeft}s</span>
                        </div>
                    </div>
                </div>

                {completed ? (
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="text-center py-10"
                    >
                        <div className="w-24 h-24 mx-auto bg-gradient-to-br from-[#10b981] to-[#047857] rounded-full flex items-center justify-center mb-8 shadow-[0_0_40px_rgba(16,185,129,0.4)]">
                            <Cpu size={48} className="text-white" />
                        </div>
                        <h2 className="text-5xl font-black mb-4">Identity <span className="text-gradient-accent">Verified</span></h2>

                        <div className="flex justify-center gap-12 mt-12">
                            <div className="text-center">
                                <p className="text-muted text-sm font-bold uppercase tracking-widest mb-2">Reflex Speed</p>
                                <div className="text-7xl font-black font-mono text-[#0ea5e9] text-glow-primary">
                                    {wpm}<span className="text-2xl text-white ml-2 uppercase">WPM</span>
                                </div>
                            </div>
                            <div className="w-1 h-20 bg-white/10 mx-4"></div>
                            <div className="text-center">
                                <p className="text-muted text-sm font-bold uppercase tracking-widest mb-2">Precision</p>
                                <div className="text-7xl font-black font-mono text-[#10b981] text-glow-primary">
                                    {Math.round(accuracy)}<span className="text-2xl text-white ml-2">%</span>
                                </div>
                            </div>
                        </div>

                        <button onClick={reset} className="btn-beast mt-12 bg-black hover:bg-[#8b5cf6]/20 border border-[#8b5cf6]/50 transition-colors">
                            <RotateCcw size={20} /> Re-Initialize Protocol
                        </button>
                    </motion.div>
                ) : (
                    <div>
                        <div
                            className="font-mono text-xl lg:text-3xl leading-relaxed tracking-wide mb-8 p-8 bg-black/40 border border-white/5 rounded-2xl relative"
                            style={{ color: '#475569' }}
                        >
                            {!started && <div className="absolute inset-0 z-10 bg-black/50 backdrop-blur-sm flex items-center justify-center rounded-2xl cursor-pointer hover:bg-black/40 transition" onClick={() => inputRef.current?.focus()}>
                                <span className="px-6 py-3 bg-[#8b5cf6] text-white font-bold rounded-full font-sans uppercase tracking-widest text-sm shadow-[0_0_30px_rgba(139,92,246,0.6)] animate-pulse">Click to Begin Input</span>
                            </div>}
                            {TEXT.split('').map((char, index) => {
                                let colorClass = '';
                                if (index < input.length) {
                                    colorClass = input[index] === char
                                        ? 'text-white drop-shadow-[0_0_8px_rgba(255,255,255,0.8)]'
                                        : 'text-[#ef4444] line-through bg-[#ef4444]/20 rounded-sm';
                                }
                                const isCursor = index === input.length && started;

                                return (
                                    <span
                                        key={index}
                                        className={clsx(
                                            colorClass,
                                            isCursor && "border-l-[3px] border-[#0ea5e9] animate-pulse ml-[1px] pl-[1px]"
                                        )}
                                    >
                                        {char}
                                    </span>
                                )
                            })}
                        </div>

                        <textarea
                            ref={inputRef}
                            className="opacity-0 absolute inset-0 w-full h-full pointer-events-none z-[-1]"
                            value={input}
                            onChange={handleChange}
                            disabled={completed}
                            autoComplete="off"
                            spellCheck="false"
                            autoCorrect="off"
                            autoCapitalize="off"
                        />

                        <div className="flex justify-between items-center text-sm font-mono tracking-widest uppercase">
                            <div className="flex items-center gap-2 text-[#0ea5e9]">
                                <Crosshair size={16} /> Data Stream: Active
                            </div>
                            <div className="text-[#8b96a5]">
                                {Math.round(accuracy)}% Accuracy Real-Time
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </motion.div>
    );
}
